import { auth } from "@/lib/auth";
import prisma from "@/lib/prisma";
import { notFound, redirect } from "next/navigation";
import Link from "next/link";
import {
    TreePine,
    Users,
    Plus,
    ArrowLeft,
    Settings,
    Heart,
    Crown,
    MapPin,
} from "lucide-react";
import MemberList from "./MemberList";

interface PageProps {
    params: Promise<{ id: string }>;
}

export default async function BaniDetailPage({ params }: PageProps) {
    const { id } = await params;
    const session = await auth();
    if (!session?.user) redirect("/login");

    const bani = await prisma.bani.findUnique({
        where: { id },
        include: {
            createdBy: { select: { name: true } },
            rootMember: { select: { id: true, fullName: true } },
            _count: { select: { members: true } },
        },
    });

    if (!bani) notFound();

    // Check access
    const baniUser = await prisma.baniUser.findUnique({
        where: { baniId_userId: { baniId: id, userId: session.user.id } },
    });

    const isAdmin = (session.user as any).role === "SUPER_ADMIN";
    if (!baniUser && !isAdmin) {
        return (
            <div className="max-w-lg mx-auto text-center py-20">
                <h2 className="text-xl font-semibold text-surface-700">Akses Ditolak</h2>
                <p className="text-surface-500 mt-2">Anda tidak memiliki akses ke bani ini.</p>
            </div>
        );
    }

    // Get stats
    const stats = await prisma.member.groupBy({
        by: ["gender", "isAlive"],
        where: { baniId: id },
        _count: true,
    });

    const totalAlive = stats.filter((s) => s.isAlive).reduce((sum, s) => sum + s._count, 0);
    const totalDeceased = stats.filter((s) => !s.isAlive).reduce((sum, s) => sum + s._count, 0);
    const totalMale = stats.filter((s) => s.gender === "MALE").reduce((sum, s) => sum + s._count, 0);
    const totalFemale = stats.filter((s) => s.gender === "FEMALE").reduce((sum, s) => sum + s._count, 0);

    const maxGeneration = await prisma.member.aggregate({
        where: { baniId: id },
        _max: { generation: true },
    });

    const members = await prisma.member.findMany({
        where: { baniId: id },
        include: {
            father: { select: { id: true, fullName: true } },
            mother: { select: { id: true, fullName: true } },
            marriagesAsHusband: {
                include: { wife: { select: { id: true, fullName: true, photo: true, gender: true } } },
                orderBy: { marriageOrder: "asc" },
            },
            marriagesAsWife: {
                include: { husband: { select: { id: true, fullName: true, photo: true, gender: true } } },
                orderBy: { marriageOrder: "asc" },
            },
        },
        orderBy: [{ generation: "asc" }, { fullName: "asc" }],
    });

    const canEdit = baniUser?.role !== "VIEWER";

    return (
        <div className="max-w-6xl mx-auto space-y-6">
            {/* Header */}
            <div className="flex items-start gap-3">
                <Link
                    href="/dashboard"
                    className="touch-target p-2 rounded-xl hover:bg-surface-100 transition-colors mt-1"
                >
                    <ArrowLeft className="w-5 h-5 text-surface-600" />
                </Link>
                <div className="flex-1">
                    <div className="flex items-center gap-3 flex-wrap">
                        <h1 className="text-2xl sm:text-3xl font-bold text-surface-900">
                            {bani.name}
                        </h1>
                        {baniUser?.role === "ADMIN" && (
                            <span className="inline-flex items-center gap-1 px-2.5 py-1 rounded-lg bg-gold-50 text-gold-700 text-xs font-medium">
                                <Crown className="w-3 h-3" /> Admin
                            </span>
                        )}
                    </div>
                    {bani.description && (
                        <p className="text-surface-500 text-sm mt-1">{bani.description}</p>
                    )}
                </div>
                {canEdit && (
                    <Link
                        href={`/dashboard/bani/${id}/settings`}
                        className="touch-target p-2 rounded-xl hover:bg-surface-100 transition-colors"
                    >
                        <Settings className="w-5 h-5 text-surface-500" />
                    </Link>
                )}
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                <div className="p-4 rounded-xl bg-white border border-surface-200">
                    <div className="flex items-center gap-2 mb-2">
                        <Users className="w-4 h-4 text-primary-500" />
                        <span className="text-xs text-surface-400">Total</span>
                    </div>
                    <p className="text-xl font-bold text-surface-900">{bani._count.members}</p>
                </div>
                <div className="p-4 rounded-xl bg-white border border-surface-200">
                    <div className="flex items-center gap-2 mb-2">
                        <Heart className="w-4 h-4 text-green-500" />
                        <span className="text-xs text-surface-400">Hidup</span>
                    </div>
                    <p className="text-xl font-bold text-green-600">{totalAlive}</p>
                </div>
                <div className="p-4 rounded-xl bg-white border border-surface-200">
                    <div className="flex items-center gap-2 mb-2">
                        <MapPin className="w-4 h-4 text-blue-500" />
                        <span className="text-xs text-surface-400">Generasi</span>
                    </div>
                    <p className="text-xl font-bold text-surface-900">
                        {(maxGeneration._max.generation ?? 0) + 1}
                    </p>
                </div>
                <div className="p-4 rounded-xl bg-white border border-surface-200">
                    <div className="flex items-center gap-2 mb-2">
                        <span className="text-sm">👨</span>
                        <span className="text-xs text-surface-400">L / P</span>
                    </div>
                    <p className="text-xl font-bold text-surface-900">
                        {totalMale} / {totalFemale}
                    </p>
                </div>
            </div>

            {/* Actions */}
            <div className="flex flex-wrap gap-3">
                <Link
                    href={`/dashboard/bani/${id}/tree`}
                    className="touch-target inline-flex items-center gap-2 px-5 py-2.5 rounded-xl bg-primary-600 text-white font-medium hover:bg-primary-500 transition-colors shadow-md shadow-primary-600/20"
                >
                    <TreePine className="w-5 h-5" />
                    Lihat Pohon Nasab
                </Link>
                {canEdit && (
                    <Link
                        href={`/dashboard/bani/${id}/members/add`}
                        className="touch-target inline-flex items-center gap-2 px-5 py-2.5 rounded-xl border border-primary-200 text-primary-700 font-medium hover:bg-primary-50 transition-colors"
                    >
                        <Plus className="w-5 h-5" />
                        Tambah Anggota
                    </Link>
                )}
            </div>

            {/* Member List */}
            <MemberList members={JSON.parse(JSON.stringify(members))} baniId={id} />
        </div>
    );
}
